package.preload["bridge.file_bus"] = function(...)
local fs = require("core.fs")
local path = require("core.path")
local json_rpc = require("bridge.json_rpc")
local logger = require("core.logger")

local file_bus = {}
local is_windows = package.config:sub(1,1) == "\\"

function file_bus.start(ctx)
  local inbox = path.join(ctx.root, ".hermes", "bus", "inbox")
  local outbox = path.join(ctx.root, ".hermes", "bus", "outbox")
  
  fs.mkdir(path.join(ctx.root, ".hermes", "bus"))
  fs.mkdir(inbox)
  fs.mkdir(outbox)
  
  logger.info("Starting File Bus bridge. Polling: " .. inbox)
  
  -- Crude pure-lua polling loop using os.execute / io.popen
  while true do
    local cmd
    if is_windows then
      cmd = 'dir /b "' .. inbox .. '\\*.json" 2>nul'
    else
      cmd = 'ls -1 "' .. inbox .. '"/*.json 2>/dev/null'
    end
    
    local p = io.popen(cmd)
    if p then
      for file_name in p:lines() do
        -- on unix ls might return full path depending on wildcard, on windows dir /b returns just filename
        file_name = path.basename(file_name)
        
        if file_name and file_name ~= "" then
          local in_path = path.join(inbox, file_name)
          local content = fs.read(in_path)
          
          if content then
            local response = json_rpc.handle(content, ctx)
            local out_path = path.join(outbox, file_name)
            
            fs.write(out_path, response)
            
            -- Delete the inbox file
            os.remove(in_path)
            logger.info("File Bus: Processed " .. file_name)
          end
        end
      end
      p:close()
    end
    
    -- Sleep to prevent CPU hogging.
    -- Pure Lua 5.1 has no os.sleep. We use a busy wait or ping hack.
    if is_windows then
      os.execute("ping -n 2 127.0.0.1 >nul")
    else
      os.execute("sleep 1")
    end
  end
end

return file_bus

end

package.preload["bridge.json_rpc"] = function(...)
local json = require("core.json")
local result = require("core.result")
local commands = require("core.commands")

local json_rpc = {}

function json_rpc.format_response(id, data)
  return json.encode({
    jsonrpc = "2.0",
    id = id,
    result = data
  })
end

function json_rpc.format_error(id, code, message)
  return json.encode({
    jsonrpc = "2.0",
    id = id,
    error = {
      code = code,
      message = message
    }
  })
end

function json_rpc.parse_request(raw_str)
  local ok, req = pcall(json.decode, raw_str)
  if not ok or type(req) ~= "table" then
    return result.fail(-32700, "Parse error", "Invalid JSON structure")
  end
  
  if req.jsonrpc ~= "2.0" or type(req.method) ~= "string" then
    return result.fail(-32600, "Invalid Request", "Missing jsonrpc version or method")
  end
  
  return result.ok("Valid request", req)
end

function json_rpc.handle(raw_str, ctx)
  local req_res = json_rpc.parse_request(raw_str)
  if not req_res.ok then
    return json_rpc.format_error(nil, req_res.error.code, req_res.error.message)
  end
  
  local req = req_res.data
  local method = req.method
  local id = req.id
  local params = req.params
  
  -- Route the method dynamically via Command Registry
  local cmd_res = commands.execute(method, ctx, params)
  
  if cmd_res.ok then
    return json_rpc.format_response(id, cmd_res.data)
  else
    return json_rpc.format_error(id, cmd_res.error.code, cmd_res.error.message)
  end
end

return json_rpc

end

package.preload["bridge.stdin_stdout"] = function(...)
local json_rpc = require("bridge.json_rpc")
local logger = require("core.logger")

local stdin_stdout = {}

function stdin_stdout.start(ctx)
  logger.info("Starting stdin/stdout bridge. Waiting for JSON-RPC payloads...")
  
  while true do
    local line = io.read("*l")
    if not line then break end -- EOF
    
    if line ~= "" then
      local response_str = json_rpc.handle(line, ctx)
      print(response_str)
      io.stdout:flush()
    end
  end
  
  logger.info("stdin/stdout bridge closed.")
end

return stdin_stdout

end

package.preload["core.cli"] = function(...)
local cli = {}

function cli.parse(args)
  local parsed = {
    command = nil,
    flags = {},
    positional = {},
    action = nil,
    target = nil
  }
  
  if not args or #args == 0 then
    return parsed
  end
  
  if args[1] == "run" then
    parsed.action = "run"
    parsed.target = args[2]
  elseif args[1] == "bridge" then
    parsed.action = "bridge"
    parsed.target = args[2] or "stdin"
  else
    parsed.action = "help"
  end
  
  parsed.command = args[1]
  
  for i = 2, #args do
    local arg = args[i]
    if arg:sub(1, 2) == "--" then
      parsed.flags[arg:sub(3)] = true
    elseif arg:sub(1, 1) == "-" then
      parsed.flags[arg:sub(2)] = true
    else
      table.insert(parsed.positional, arg)
    end
  end
  
  return parsed
end

return cli

end

package.preload["core.commands"] = function(...)
local result = require("core.result")
local logger = require("core.logger")

local commands = {
  _registry = {}
}

function commands.register(name, handler)
  if type(handler) ~= "function" then
    logger.error("Failed to register command '" .. name .. "': handler must be a function")
    return false
  end
  
  if commands._registry[name] then
    logger.warn("Overwriting command '" .. name .. "'")
  end
  
  commands._registry[name] = handler
  return true
end

function commands.execute(name, ctx, params)
  local handler = commands._registry[name]
  if not handler then
    return result.fail(-32601, "Method not found", "Command '" .. name .. "' is not registered")
  end
  
  local ok, res = pcall(handler, ctx, params)
  if not ok then
    logger.error("Command execution failed: " .. tostring(res))
    return result.fail(-32000, "Internal error", "Command crashed: " .. tostring(res))
  end
  
  -- Assuming handlers return a result.ok() or result.fail()
  if type(res) == "table" and res.ok ~= nil then
    return res
  else
    -- Wrap raw returns
    return result.ok("Command executed", res)
  end
end

-- Register core default commands
commands.register("ping", function(ctx, params)
  return result.ok("pong", "pong")
end)

commands.register("project.info", function(ctx, params)
  return result.ok("info", { name = ctx.project.name, type = ctx.project.type })
end)

return commands

end

