package.preload["core.events"] = function(...)
local logger = require("core.logger")

local events = {
  _listeners = {}
}

function events.subscribe(event_name, callback)
  if type(callback) ~= "function" then return false end
  
  if not events._listeners[event_name] then
    events._listeners[event_name] = {}
  end
  
  table.insert(events._listeners[event_name], callback)
  return true
end

function events.dispatch(event_name, payload)
  local handlers = events._listeners[event_name]
  if not handlers then return end
  
  for _, handler in ipairs(handlers) do
    local ok, err = pcall(handler, payload)
    if not ok then
      logger.error("Event handler failed for " .. event_name .. ": " .. tostring(err))
    end
  end
end

return events

end

