package.preload["core.json"] = function(...)
-- A minimal pure-lua JSON encoder/decoder for Hermes
local json = {}

local function escape_str(s)
  local in_char  = {'\\', '"', '/', '\b', '\f', '\n', '\r', '\t'}
  local out_char = {'\\', '"', '/',  'b',  'f',  'n',  'r',  't'}
  for i, c in ipairs(in_char) do
    s = s:gsub(c, '\\' .. out_char[i])
  end
  return s
end

function json.encode(val)
  local t = type(val)
  if t == "nil" then return "null"
  elseif t == "boolean" then return tostring(val)
  elseif t == "number" then return tostring(val)
  elseif t == "string" then return '"' .. escape_str(val) .. '"'
  elseif t == "table" then
    local is_array = true
    local max = 0
    for k, _ in pairs(val) do
      if type(k) ~= "number" or k <= 0 or math.floor(k) ~= k then
        is_array = false
        break
      end
      if k > max then max = k end
    end
    
    local parts = {}
    if is_array then
      for i = 1, max do
        table.insert(parts, json.encode(val[i]))
      end
      return "[" .. table.concat(parts, ",") .. "]"
    else
      for k, v in pairs(val) do
        table.insert(parts, '"' .. escape_str(tostring(k)) .. '":' .. json.encode(v))
      end
      return "{" .. table.concat(parts, ",") .. "}"
    end
  end
  return '"{unsupported}"'
end

-- Minimal crude JSON decoder for Hermes IPC
-- Handles basic flat structures and simple nested ones
function json.decode(str)
  -- For an MVP bridge, we'll try to extract fields using simple patterns
  -- A real implementation should use a proper tokenizer.
  -- To keep it self-contained without crashing, we return a mocked table
  -- if we detect a JSON RPC call: {"jsonrpc": "2.0", "method": "...", "params": {...}, "id": 1}
  
  local result = {}
  
  local method = str:match('"method"%s*:%s*"([^"]+)"')
  local id = str:match('"id"%s*:%s*(%d+)')
  local jsonrpc = str:match('"jsonrpc"%s*:%s*"([^"]+)"')
  
  if jsonrpc then result.jsonrpc = jsonrpc end
  if method then result.method = method end
  if id then result.id = tonumber(id) end
  
  -- Crude params extraction
  result.params = {}
  local params_str = str:match('"params"%s*:%s*{(.-)}')
  if params_str then
    for k, v in params_str:gmatch('"([^"]+)"%s*:%s*"([^"]+)"') do
      result.params[k] = v
    end
  end
  
  return result
end

return json

end

package.preload["core.logger"] = function(...)
