local function log(level, msg)
  if levels[level] >= (levels[logger.level] or 2) then
    local prefix = string.upper(level)
    print(string.format("[Hermes] [%s] %s", prefix, msg))
  end
end

function logger.debug(msg) log("debug", msg) end
