package.preload["core.manifest"] = function(...)
local fs = require("core.fs")
local path = require("core.path")

local manifest = {}

local default_manifest = {
  generated_files = {},
  adapters = {},
  version = 1,
  last_updated = os.time()
}

function manifest.load(root_dir)
  local manifest_path = path.join(root_dir, ".hermes", "manifest.lua")
  if not fs.exists(manifest_path) then
    return default_manifest
  end
  
  local chunk = loadfile(manifest_path)
  if chunk then
    local ok, m = pcall(chunk)
    if ok and type(m) == "table" then
      return m
    end
  end
  
  return default_manifest
end

function manifest.save(root_dir, m)
  local manifest_path = path.join(root_dir, ".hermes", "manifest.lua")
  
  m.last_updated = os.time()
  
  local lines = { "return {" }
  
  lines[#lines+1] = '  version = ' .. tostring(m.version) .. ','
  lines[#lines+1] = '  last_updated = ' .. tostring(m.last_updated) .. ','
  
  lines[#lines+1] = '  generated_files = {'
  for _, f in ipairs(m.generated_files or {}) do
    lines[#lines+1] = string.format('    "%s",', f)
  end
  lines[#lines+1] = '  },'
  
  lines[#lines+1] = '  adapters = {'
  for _, a in ipairs(m.adapters or {}) do
    lines[#lines+1] = string.format('    "%s",', a)
  end
  lines[#lines+1] = '  }'
  
  lines[#lines+1] = "}"
  
  local content = table.concat(lines, "\n")
  return fs.write(manifest_path, content)
end

function manifest.track_file(m, filepath)
  for _, f in ipairs(m.generated_files) do
    if f == filepath then return end
  end
  table.insert(m.generated_files, filepath)
end

function manifest.track_adapter(m, adapter_name)
  for _, a in ipairs(m.adapters) do
    if a == adapter_name then return end
  end
  table.insert(m.adapters, adapter_name)
end

return manifest

end

package.preload["core.path"] = function(...)
local path = {}

path.sep = package.config:sub(1, 1) or "/"

function path.join(...)
  local parts = {...}
  local res = parts[1]
  for i = 2, #parts do
    if parts[i] and parts[i] ~= "" then
      res = res .. path.sep .. parts[i]
    end
  end
  -- simple normalization for double separators
  if path.sep == "/" then
    res = res:gsub("//+", "/")
  else
    res = res:gsub("\\\\+", "\\")
  end
  return res
end

function path.dirname(p)
  local pattern = "(.*)[" .. path.sep .. "/]"
  local dir = p:match(pattern)
  if not dir then return "." end
  return dir
end

function path.basename(p)
  local pattern = ".*[" .. path.sep .. "/](.*)"
  local base = p:match(pattern)
  if not base then return p end
  return base
end

return path

end

package.preload["core.plugins"] = function(...)
local fs = require("core.fs")
local path = require("core.path")
local logger = require("core.logger")
local events = require("core.events")
local commands = require("core.commands")

local plugins = {}
local is_windows = package.config:sub(1,1) == "\\"

function plugins.load_all(ctx)
  local plugin_dir = path.join(ctx.root, ".hermes", "plugins")
  
  if not fs.exists(plugin_dir) then
    return
  end
  
  local cmd
  if is_windows then
    cmd = 'dir /b "' .. plugin_dir .. '\\*.lua" 2>nul'
  else
    cmd = 'ls -1 "' .. plugin_dir .. '"/*.lua 2>/dev/null'
  end
  
  local p = io.popen(cmd)
  if p then
    for file_name in p:lines() do
      file_name = path.basename(file_name)
      if file_name and file_name ~= "" then
        local plugin_path = path.join(plugin_dir, file_name)
        
        local chunk, err = loadfile(plugin_path)
        if chunk then
          -- Inject API into plugin environment
          local env = setmetatable({
            hermes = {
              events = events,
              commands = commands,
              logger = logger,
              ctx = ctx
            }
          }, { __index = _G })
          
          setfenv(chunk, env)
          
          local ok, p_err = pcall(chunk)
          if ok then
            logger.info("Loaded plugin: " .. file_name)
          else
            logger.error("Failed to initialize plugin " .. file_name .. ": " .. tostring(p_err))
          end
        else
          logger.error("Failed to parse plugin " .. file_name .. ": " .. tostring(err))
        end
      end
    end
    p:close()
  end
end

return plugins

end

package.preload["core.project_detect"] = function(...)
local fs = require("core.fs")
local path = require("core.path")

local detect = {}

local signatures = {
  node = { "package.json", "node_modules" },
  rust = { "Cargo.toml", "src/main.rs" },
  python = { "pyproject.toml", "requirements.txt", "setup.py" },
  tauri = { "src-tauri/tauri.conf.json", "src-tauri/Cargo.toml" },
  unity = { "Assets", "ProjectSettings/ProjectVersion.txt" },
  go = { "go.mod", "main.go" },
  dotnet = { "*.csproj", "*.sln" } -- simple matching
}

function detect.scan(root_dir)
  local results = {}
  local files = {} -- cache
  
  local function file_exists(rel_path)
    if files[rel_path] ~= nil then return files[rel_path] end
    local full = path.join(root_dir, rel_path)
    local exists = fs.exists(full)
    files[rel_path] = exists
    return exists
  end

  for ptype, sigs in pairs(signatures) do
    local matched_sigs = {}
    local confidence = 0
    
    for _, sig in ipairs(sigs) do
      if not sig:find("%*") then -- simple exact match for now
        if file_exists(sig) then
          table.insert(matched_sigs, sig)
          confidence = confidence + (1.0 / #sigs)
        end
      end
    end
    
    if confidence > 0 then
      table.insert(results, {
        id = ptype,
        matched = true,
        confidence = confidence,
        signals = matched_sigs,
        reason = "Found: " .. table.concat(matched_sigs, ", ")
      })
    end
  end
  
  -- Sort by confidence
  table.sort(results, function(a, b) return a.confidence > b.confidence end)
  
  return results
end

return detect

end

