package.preload["core.templates"] = function(...)
local templates = {}

function templates.render(template_string, variables)
  if not template_string then return "" end
  
  local result = template_string:gsub("{{(.-)}}", function(key)
    -- trim whitespace
    key = key:match("^%s*(.-)%s*$")
    
    local value = variables[key]
    if value == nil then
      return "{{" .. key .. "}}"
    end
    return tostring(value)
  end)
  
  return result
end

-- Generates the standard header for all Hermes-generated files
function templates.header()
  return [[
-- Generated by Hermes.lua
-- Do not edit unless you know what you are doing.
-- This file is tracked in .hermes/manifest.lua.
-- Regenerate with: lua hermes.lua wire
]]
end

return templates

end

