package.preload["installers.install"] = function(...)
local result = require("core.result")
local config = require("core.config")
local logger = require("core.logger")
local fs = require("core.fs")
local detect = require("core.project_detect")
local manifest = require("core.manifest")
local generic_adapter = require("adapters.generic")
local cli_adapter = require("adapters.cli")
local node_adapter = require("adapters.node")
local tauri_adapter = require("adapters.tauri")
local python_adapter = require("adapters.python")
local unity_adapter = require("adapters.unity")
local web_adapter = require("adapters.web")

local install = {}

local ADAPTERS = { generic_adapter, cli_adapter, node_adapter, tauri_adapter, python_adapter, unity_adapter, web_adapter }

function install.init(ctx)
  logger.info("Running init...")
  local ok, err = config.generate(ctx.root)
  if not ok and err ~= "Config already exists" then
    logger.error("Init failed: " .. err)
    return result.fail("INIT_FAIL", err)
  end
  
  -- Ensure manifest exists
  ctx.manifest = manifest.load(ctx.root)
  manifest.save(ctx.root, ctx.manifest)
  
  return result.ok("Init successful")
end

function install.run(ctx, dry_run)
  logger.info("Starting Hermes installation...")
  if dry_run then
    logger.info("[DRY RUN] No changes will be written to disk.")
  end
  
  local r = install.init(ctx)
  if not r.ok then return r end
  
  -- Project root detection
  local detections = detect.scan(ctx.root)
  logger.info(string.format("Detected %d potential project matches.", #detections))
  
  local chosen_adapters = {}
  for _, d in ipairs(detections) do
    logger.info(string.format("- Detected: %s (Confidence: %.2f) - %s", d.id, d.confidence, d.reason))
    table.insert(chosen_adapters, d.id)
  end
  
  if #chosen_adapters == 0 then
    logger.warn("No specific project type detected. Using generic fallback.")
    table.insert(chosen_adapters, "generic")
  end
  
  table.insert(chosen_adapters, "cli") -- Always wire CLI for Phase 2
  
  logger.info("Wiring adapters: " .. table.concat(chosen_adapters, ", "))
  
  for _, adapter_id in ipairs(chosen_adapters) do
    for _, a in ipairs(ADAPTERS) do
      if a.id == adapter_id then
        local wire_res = a.wire(ctx, dry_run)
        if not wire_res.ok then
          logger.warn("Failed to wire adapter " .. a.id .. ": " .. wire_res.error.message)
        end
      end
    end
  end
  
  if not dry_run then
    manifest.save(ctx.root, ctx.manifest)
  end
  
  logger.info("--- Hermes Install Report ---")
  logger.info("Project: " .. (ctx.project.name or "Unknown"))
  logger.info("Detected: " .. table.concat(chosen_adapters, " + "))
  logger.info("Installed: yes")
  
  return result.ok("Install successful")
end

return install

end

-- main.lua
-- The main entry point for the Hermes framework

local cli = require("core.cli")
local context = require("core.context")
local logger = require("core.logger")
local install = require("installers.install")
local doctor = require("installers.doctor")
local plugins = require("core.plugins")
local bridge_stdin = require("bridge.stdin_stdout")
local bridge_file_bus = require("bridge.file_bus")

local is_neurodeck = (_G.registerCommand ~= nil)

local function run_cli(args)
  local parsed = cli.parse(args)
  local ctx = context.build(".")
  
  -- Load all external plugins now that context is ready
  plugins.load_all(ctx)
  
  if not parsed.command then
    logger.info("Usage: hermes.lua <command> [flags]")
    logger.info("Commands: init, install, doctor")
    return
  end
  
  local cmd = parsed.command
  if cmd == "init" then
    local res = install.init(ctx)
    if not res.ok then logger.error(res.error.message) end
  elseif cmd == "install" then
    local dry_run = parsed.flags["dry-run"]
    local res = install.run(ctx, dry_run)
    if not res.ok then logger.error(res.error.message) end
  elseif cmd == "doctor" then
    local res = doctor.run(ctx)
    if not res.ok then logger.error(res.error.message) end
  elseif cmd == "bridge" then
    local target = parsed.target
    if target == "filebus" then
      bridge_file_bus.start(ctx)
    else
      bridge_stdin.start(ctx)
    end
  else
    logger.error("Unknown command: " .. cmd)
  end
end

if is_neurodeck then
  _G.registerCommand("hermes", function(args_str)
    -- Parse args_str (e.g. "doctor" or "install --dry-run")
    local args = {}
    if args_str and args_str ~= "" then
      for word in string.gmatch(args_str, "%S+") do
        table.insert(args, word)
      end
    end
    
    if #args == 0 then
      -- Default behavior: switch persona (legacy compatibility)
      if _G.setPersona then
        local ok = _G.setPersona("Hermes")
        if ok then
          return "System: Active Persona switched to Hermes (Framework mode loaded)."
        end
      end
      return "Hermes Framework is active. Use `/hermes doctor` or `/hermes init`."
    end
    
    -- Redirect output from logger to a string buffer for NEURODECK
    local output_buffer = {}
    local orig_info = logger.info
    local orig_error = logger.error
    local orig_warn = logger.warn
    
    local function buffer_log(msg) table.insert(output_buffer, msg) end
    logger.info = buffer_log
    logger.error = buffer_log
    logger.warn = buffer_log
    
    run_cli(args)
    
    -- Restore logger
    logger.info = orig_info
    logger.error = orig_error
    logger.warn = orig_warn
    
    return table.concat(output_buffer, "\n")
  end)
  
  print("[Plugin] Hermes Framework loaded. Type /hermes to switch persona, or /hermes doctor for framework diagnostic.")
else
  -- Standalone CLI mode
  if arg then
    run_cli(arg)
  end
end
